sys_script_include.script:
function GetParam(strParam,callbackCheckParameter)
{
	strParam = GetStringValue(strParam);
	if (strParam == '')
	{
		return '';
	}
	var strInsecureValue = '';
	if (typeof RP != 'undefined')
	{
		strInsecureValue =  GetStringValue(RP.getParameterValue(strParam));
	}
	if (typeof gs.action.getGlideURI != 'undefined')
	{
		// This also covers scripted REST API endpoints

		var glideUri = RunScriptInGlobalScope('result = gs.action.getGlideURI();');
		if (glideUri != null)
		{
			strInsecureValue = GetStringValue(glideUri.get(strParam));
			if (strInsecureValue == '')
			{
				strInsecureValue = GetStringValue(glideUri.get('sysparm_'+strParam));
			}
		}
	}

	var strValue = '';
	if (IsFunction(callbackCheckParameter) == false)
	{
		callbackCheckParameter = IsSecureParameterValue;
	}
	if (callbackCheckParameter(strInsecureValue) == true)
	{
		strValue = strInsecureValue;
	}
	return strValue;
}
